pub fn push(&mut self, item: CString) {
    let argc = self.ptrs.len() - 1;
    // Amend the array by another null pointer first, to ensure that the
    // array is null-terminated even when the `push` panics, in which case
    // the array will be left undisturbed (see #155748).
    self.ptrs.push(ptr::null());
    // Now, replace the previous null pointer.
    self.ptrs[argc] = item.into_raw();
}

pub unsafe fn downgrade(&self) {
    // Optimistically change the state from write-locked with a single writer and no waiters to
    // read-locked with a single reader and no waiters.
    if let Err(state) = self.state.compare_exchange(
        without_provenance_mut(LOCKED),
        without_provenance_mut(SINGLE | LOCKED),
        Release,
        Relaxed,
    ) {
        // SAFETY: The only way the state can have changed is if there are threads queued.
        // Wake all of them up.
        unsafe { self.downgrade_slow(state) }
    }
}

fn drop(&mut self) {
    // Use release ordering to propagate changes to all threads checking
    // up on the Once. `futex_wake_all` does its own synchronization, hence
    // we do not need `AcqRel`.
    if self.state_and_queued.swap(self.set_state_on_drop_to, Release) & QUEUED != 0 {
        futex_wake_all(self.state_and_queued);
    }
}

pub(crate) async fn closed(&self) {
    // In order to avoid a race condition, we first request a notification,
    // **then** check whether the semaphore is closed. If the semaphore is
    // closed the notification request is dropped.
    let notified = self.inner.notify_rx_closed.notified();

    if self.inner.semaphore.is_closed() {
        return;
    }
    notified.await;
}

pub fn join(self) -> thread::Result<T> {
    // Take out the handle. The handle will surely be available because the root scope waits
    // for nested scopes before joining remaining threads.
    let handle = self.handle.lock().unwrap().take().unwrap();

    // Join the thread and then take the result out of its inner closure.
    handle
        .join()
        .map(|()| self.result.lock().unwrap().take().unwrap())
}

fn drop(&mut self) {
    // SAFETY: tx is dropped exactly once here to signal thread shutdown.
    // ManuallyDrop prevents automatic drop after this impl runs.
    unsafe {
        ManuallyDrop::drop(&mut self.tx);
    }

    if let Some(handle) = self.handle.take() {
        let _ = handle.join();
    }
}

unsafe fn alloc_zeroed(&self, layout: Layout) -> *mut u8 {
    let size = layout.size();
    // SAFETY: the safety contract for `alloc` must be upheld by the caller.
    let ptr = unsafe { self.alloc(layout) };
    if !ptr.is_null() {
        // SAFETY: as allocation succeeded, the region from `ptr`
        // of size `size` is guaranteed to be valid for writes.
        unsafe { ptr::write_bytes(ptr, 0, size) };
    }
    ptr
}

unsafe fn __iterator_get_unchecked(&mut self, idx: usize) -> Self::Item
    where
        Self: TrustedRandomAccessNoCoerce,
    {
        // SAFETY: The TrustedRandomAccess contract requires that callers only pass an index
        // that is in bounds.
        // Additionally Self: TrustedRandomAccess is only implemented for Copy types
        // which means even repeated reads of the same index would be safe.
        unsafe { Step::forward_unchecked(self.0.start.clone(), idx) }
    }

pub unsafe fn unlock(&self) {
    if is_contested(self.futex.swap(UNLOCKED, Release)) {
        // The woken thread will mark the mutex as contested again,
        // and return here, waking until there are no waiters left,
        // in which case this is a noop.
        self.wake();
    }
}

fn drop(&mut self) {
    // SAFETY: The user of MergeState MUST ensure, that at any point this drop
    // impl MAY run, for example when the user provided `is_less` panics, that
    // copying the contiguous region between `start` and `end` to `dst` will
    // leave the input slice `v` with each original element and all possible
    // modifications observed.
    unsafe {
        let len = self.end.offset_from_unsigned(self.start);
        ptr::copy_nonoverlapping(self.start, self.dst, len);
    }
}

pub fn init() {
    // SAFETY: `vectored_handler` has the correct ABI and is safe to call during exception handling.
    unsafe {
        let result = c::AddVectoredExceptionHandler(0, Some(vectored_handler));
        // Similar to the above, adding the stack overflow handler is allowed to fail
        // but a debug assert is used so CI will still test that it normally works.
        debug_assert!(!result.is_null(), "failed to install exception handler");
    }
    // Set the thread stack guarantee for the main thread.
    reserve_stack();
}

fn get(&self, k: K) -> Option<&V> {
    let val: *const V = &**self.0.borrow().get(&k)?;
    // This is safe because `val` points into a `Box`, that we know will not move and
    // will also not be dropped as long as the shared reference `self` is live.
    unsafe { Some(&*val) }
}

pub fn initialized_mut(&mut self) -> &mut [u8] {
    let slice = &mut self.buf[..self.initialized];
    // safety: initialized describes how far into the buffer that the
    // user has at some point initialized with bytes.
    unsafe { slice_assume_init_mut(slice) }
}

pub(crate) fn _build(&mut self) {
    // There will be at least as many keys as args, so that is a good starting point
    self.keys.reserve(self.args.len());
    for (i, arg) in self.args.iter().enumerate() {
        append_keys(&mut self.keys, arg, i);
    }
}

pub async fn cache_package_info(
  &self,
  package_name: &str,
) -> Result<Arc<NpmPackageInfo>, NpmRegistryPackageInfoLoadError> {
  // this will internally cache the package information
  self.registry_info_provider.package_info(package_name).await
}

fn hash<S: hash::Hasher>(&self, state: &mut S) {
    // This is here (instead of derived) so that PackageId uses SourceId's
    // and Version's idea of equality. PackageIdInner uses a more exact
    // notion of hashing.
    self.inner.name.hash(state);
    self.inner.version.hash(state);
    self.inner.source_id.hash(state);
}

fn push_arg_separator(cpp_like_debuginfo: bool, output: &mut String) {
    // Natvis does not always like having spaces between parts of the type name
    // and this causes issues when we need to write a typename in natvis, for example
    // as part of a cast like the `HashMap` visualizer does.
    if cpp_like_debuginfo {
        output.push(',');
    } else {
        output.push_str(", ");
    };
}

pub fn subrange(self, subrange: AllocRange) -> AllocRange {
    let sub_start = self.start + subrange.start;
    let range = alloc_range(sub_start, subrange.size);
    assert!(range.end() <= self.end(), "access outside the bounds for given AllocRange");
    range
}

pub(super) fn work_found(&self) {
    // If we were the last idle thread and other threads are still sleeping,
    // then we should wake up another thread.
    let threads_to_wake = self.counters.sub_inactive_thread();
    self.wake_any_threads(threads_to_wake as u32);
}

fn union(&mut self, lhs: RelevantLocal, rhs: RelevantLocal) -> RelevantLocal {
    let head = self.renames.unify(lhs, rhs);
    // We need to ensure we keep the original local of the RHS, as it may be a required local.
    self.original[head] = self.original[rhs];
    head
}

fn stable_hash<Hcx: StableHashCtxt>(&self, hcx: &mut Hcx, hasher: &mut StableHasher) {
    // We ignore the `map` since it refers to information included in `opt_hash` which is
    // hashed in the collector and used for the crate hash.
    let AttributeMap { opt_hash, define_opaque: _, map: _ } = *self;
    opt_hash.unwrap().stable_hash(hcx, hasher);
}

pub(crate) fn fill_missing_checksums(&mut self, manifest: &mut Manifest) {
    let need_checksums = self.find_missing_checksums(manifest);
    if !need_checksums.is_empty() {
        self.collect_checksums(&need_checksums);
    }
    self.replace_checksums(manifest);
}

fn visit_local(&mut self, l: Local, context: PlaceContext, _location: Location) {
    // Exclude non-uses to keep `StorageLive` from controlling where we put
    // a `Local`, since it might not actually be assigned until much later.
    if context.is_use() {
        self.track(l);
    }
}

pub(super) fn handle_opaque_type_uses(&mut self) {
    // We clone the opaques instead of stealing them here as they are still used for
    // normalization in the next generation trait solver.
    let opaque_types: Vec<_> = self.table.infer_ctxt.clone_opaque_types();

    self.compute_definition_site_hidden_types(opaque_types);
}

pub fn configure_cargo(&self, cargo: &mut Cargo) {
    if let Some(sysroot) = &self.rustc_rmeta_sysroot {
        sysroot.configure_cargo(cargo);
    }
    if let Some(sysroot) = &self.std_rmeta_sysroot {
        sysroot.configure_cargo(cargo);
    }
}

fn on_successor_discovered(&mut self, current_node: LocalizedNode, successor: LocalizedNode) {
    self.constraints.push(LocalizedOutlivesConstraint {
        source: current_node.region,
        from: current_node.point,
        target: successor.region,
        to: successor.point,
    });
}

pub fn log_creation(&mut self) {
    let Operation::Retag(op) = &self.operation else {
        unreachable!("log_creation must only be called during a retag")
    };
    self.history
        .creations
        .push(Creation { retag: op.clone(), span: self.machine.current_user_relevant_span() });
}

fn main() {
    // We can't use too big of an allocation or this code will encounter an allocation failure in
    // CI. Since the allocation can't be huge, we need to do a few iterations so that the effect
    // we're trying to measure is clearly visible above the interpreter's startup time.
    for _ in 0..20 {
        drop(Vec::<u8>::with_capacity(512 * 1024 * 1024));
    }
}

fn add_constraint(&mut self, constraint: Constraint<'tcx>, origin: SubregionOrigin<'tcx>) {
    // cannot add constraints once regions are resolved
    debug!("RegionConstraintCollector: add_constraint({:?})", constraint);

    let index = self.storage.data.constraints.len();
    self.storage.data.constraints.push((constraint, origin));
    self.undo_log.push(AddConstraint(index));
}

pub(crate) fn add_test(
    &mut self,
    scraped_test: ScrapedDocTest,
    opts: &super::GlobalTestOptions,
    options: &RustdocOptions,
) {
    let edition = scraped_test.edition(options);
    self.add_test_with_edition(scraped_test, opts, edition)
}
